import json
import psycopg2

def lambda_handler(event, context):
    conn = None
    try:
        conn = psycopg2.connect(database="production", user="admin", password="password", host="internal-db.us-east-1.rds.amazonaws.com", port=5432)
        cur = conn.cursor()
        # Replace this with your custom SQL query
        cur.execute("SELECT * FROM your_table_name")
        results = cur.fetchall()
        response = { "data": [dict(zip([column[0] for column in cur.description], row)) for row in results] }
    except Exception as e:
        response = {"error": str(e)}
    finally:
        if conn:
            conn.close()
    return {
        'statusCode': 200,
        'body': json.dumps(response)
    }